// =============================================================
// POST /api/admin-backfill-times
//
// Sets `scheduledAt` on schedule matches that are missing it. The blind-
// lineup reveal gate reads `scheduledAt` (a full ISO timestamp) — matches
// generated by admin-generate-schedule start with scheduledAt: null, and
// since June 2026 a null time FAILS CLOSED (lineups never reveal). This
// endpoint backfills real timestamps so the reveal works.
//
// Body: {
//   circuit: 'I',                          // circuit letter (required)
//   times: { "1": "<ISO>", "2": "<ISO>" }, // week → match start timestamp
//   overwrite: false                       // also replace existing times
// }
//
// The admin UI computes the ISO strings in the BROWSER's timezone (week
// date + 7:00 PM local), so server UTC never skews match-night times.
//
// Admin-only.
// =============================================================

import { getStore } from '@netlify/blobs';
import { verifyAdminSession, unauthResponse } from './lib/auth.js';

export default async (req) => {
  if (req.method !== 'POST') return new Response('Method not allowed', { status: 405 });
  const verified = await verifyAdminSession(req);
  if (!verified.valid) return unauthResponse(verified.error);
  const admin = verified.payload;

  let body;
  try { body = await req.json(); } catch { return json({ error: 'invalid JSON body' }, 400); }

  const circuit = String(body?.circuit || '').toUpperCase();
  const times = body?.times || {};
  const overwrite = !!body?.overwrite;
  if (!circuit) return json({ error: 'circuit required' }, 400);
  if (!Object.keys(times).length) return json({ error: 'times required (week → ISO timestamp)' }, 400);

  // Validate every timestamp up front — a bad one would silently break the
  // reveal gate for that whole week.
  for (const [week, iso] of Object.entries(times)) {
    if (Number.isNaN(Date.parse(iso))) {
      return json({ error: `times["${week}"] is not a parseable timestamp: ${iso}` }, 400);
    }
  }

  try {
    const store = getStore('schedule');
    const now = new Date().toISOString();
    const result = { circuit, weeksTouched: 0, matchesUpdated: 0, matchesSkipped: 0 };

    const { blobs } = await store.list({ prefix: `schedule/${circuit}/` });
    for (const b of blobs) {
      const data = await store.get(b.key, { type: 'json' }).catch(() => null);
      if (!data?.matches) continue;
      const week = String(data.week || '');
      const iso = times[week];
      if (!iso) continue;

      let changed = false;
      for (const m of data.matches) {
        if (m.scheduledAt && !overwrite) { result.matchesSkipped++; continue; }
        m.scheduledAt = iso;
        result.matchesUpdated++;
        changed = true;
      }
      if (changed) {
        data.updatedAt = now;
        data.updatedBy = admin.email || 'admin';
        await store.setJSON(b.key, data);
        result.weeksTouched++;
      }
    }

    return json({ ok: true, ...result });
  } catch (err) {
    console.error('admin-backfill-times error:', err);
    return json({ error: 'Backfill failed', detail: err.message }, 500);
  }
};

function json(body, status = 200) {
  return new Response(JSON.stringify(body), {
    status, headers: { 'Content-Type': 'application/json', 'Cache-Control': 'private, no-store' },
  });
}

export const config = { path: '/.netlify/functions/admin-backfill-times' };
